    assert!(args.contains(&format!("HTTP_PROXY={expected_url}")));
    assert!(args.contains(&format!("https_proxy={expected_url}")));
    assert!(args.contains(&"NO_PROXY=localhost,127.0.0.1,::1".to_string()));
    assert!(args.contains(&"no_proxy=localhost,127.0.0.1,::1".to_string()));
}

