pub async fn api_clean_all_containers_handler(State(state): State<AppState>) -> impl IntoResponse {
    let prefix = state
        .gateway
        .sandbox_router
        .as_ref()
        .map(|r| {
            r.config()
                .container_prefix
                .clone()
                .unwrap_or_else(|| "moltis-sandbox".to_string())
        })
        .unwrap_or_else(|| "moltis-sandbox".to_string());
