  1→const { expect, test } = require("../base-test");
  2→const { navigateAndWait, waitForWsConnected, watchPageErrors } = require("../helpers");
  3→
  4→function isRetryableRpcError(message) {
  5→	if (typeof message !== "string") return false;
  6→	return message.includes("WebSocket not connected") || message.includes("WebSocket disconnected");
  7→}
  8→
  9→async function sendRpcFromPage(page, method, params) {
 10→	let lastResponse = null;
 11→	for (let attempt = 0; attempt < 40; attempt++) {
 12→		if (attempt > 0) {
 13→			await waitForWsConnected(page);
 14→			await page.waitForTimeout(100);
 15→		}
 16→		lastResponse = await page
 17→			.evaluate(
 18→				async ({ methodName, methodParams }) => {
 19→					var appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
 20→					if (!appScript) throw new Error("app module script not found");
 21→					var appUrl = new URL(appScript.src, window.location.origin);
 22→					var prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
 23→					var helpers = await import(`${prefix}js/helpers.js`);
 24→					return helpers.sendRpc(methodName, methodParams);
 25→				},
 26→				{
 27→					methodName: method,
 28→					methodParams: params,
 29→				},
 30→			)
 31→			.catch((error) => ({ ok: false, error: { message: error?.message || String(error) } }));
 32→
 33→		if (lastResponse?.ok) return lastResponse;
 34→		if (!isRetryableRpcError(lastResponse?.error?.message)) return lastResponse;
 35→	}
 36→
 37→	return lastResponse;
 38→}
 39→
 40→async function expectRpcOk(page, method, params) {
 41→	const response = await sendRpcFromPage(page, method, params);
 42→	expect(response?.ok, `RPC ${method} failed: ${response?.error?.message || "unknown error"}`).toBeTruthy();
 43→	return response;
 44→}
