		await expectRpcOk(page, "system-event", {
			event: "chat",
			payload: {
				sessionKey: "main",
				state: "tool_call_end",
				toolCallId: "test-csv-call",
				toolName: "send_document",
				success: true,
				result: {
					document_ref: "media/main/ghi789_data.csv",
